import { cn } from '@/utils/cn';
import { getColor } from '@utils/helper';
import { mergeProps, ParentComponent, Show } from 'solid-js';
import { DividerProps } from './divider.types';

const thicknessClass: Record<NonNullable<DividerProps['thickness']>, string> = {
  1: 'border-px',
  2: 'border-[2px]',
  3: 'border-[3px]',
  4: 'border-[4px]',
};

const Divider: ParentComponent<DividerProps> = p => {
  p = mergeProps(
    {
      orientation: 'horizontal' as const,
      variant: 'solid' as const,
      align: 'center' as const,
      thickness: 1 as const,
      color: 'secondary' as const,
    },
    p,
  );

  const isVertical = () => p.orientation === 'vertical';

  const lineClass = () =>
    cn(
      p.color ? 'divi3' : 'divi4',
      isVertical() ? 'border-l' : 'border-t',
      thicknessClass[p.thickness!],
      p.variant === 'dashed' && 'border-dashed',
      p.variant === 'dotted' && 'border-dotted',
      p.class?.line,
    );

  return (
    <Show
      when={!!p.children}
      fallback={
        <hr
          role="separator"
          aria-orientation={p.orientation}
          class={cn(
            'divi1',
            p.color ? 'divi3' : 'divi4',
            isVertical() ? 'h-auto self-stretch border-l' : 'w-full border-t',
            thicknessClass[p.thickness!],
            p.variant === 'dashed' && 'border-dashed',
            p.variant === 'dotted' && 'border-dotted',
            getColor(p.color),
            p.class?.root,
          )}
        />
      }
    >
      <div
        role="separator"
        aria-orientation={p.orientation}
        class={cn(
          'divi2',
          isVertical() ? 'flex-col self-stretch' : 'w-full flex-row',
          getColor(p.color),
          p.class?.root,
        )}
      >
        <div
          class={cn(lineClass(), p.align === 'center' || p.align === 'end' ? 'flex-1' : 'w-4')}
        />

        <span
          class={cn(
            'divi5',
            p.color ? 'divi6' : 'divi7',
            isVertical() ? 'py-3' : 'px-3',
            p.class?.content,
          )}
        >
          {p.children}
        </span>

        <div
          class={cn(lineClass(), p.align === 'center' || p.align === 'start' ? 'flex-1' : 'w-4')}
        />
      </div>
    </Show>
  );
};

export { Divider };
